        for i, x in enumerate(a):
            if prod_all == 0:
                # Recompute product for this index robustly (n<=9, ok)
                p = 1
                for j, y in enumerate(a):
                    if j == i:
                        p *= (y + 1)
                    else:
                        p *= y
                best = max(best, p)
            else:
                # prod_all non-zero => all digits are non-zero
                # replace a[i] with a[i]+1
                p = prod_all // x * (x + 1)
                if p > best:
                    best = p
        out.append(str(best))
    sys.stdout.write("\n".join(out))

