import sys

def solve():
    it = iter(sys.stdin.read().strip().split())
    t = int(next(it))
    out = []
    for _ in range(t):
        n = int(next(it))
        digits = [int(next(it)) for _ in range(n)]

        base_prod = 1
        zero_cnt = 0
        for d in digits:
            if d == 0:
                zero_cnt += 1
            base_prod *= d

        if zero_cnt >= 2:
            # Any single +1 can turn at most one zero into 1, so product stays 0.
            out.append("0")
            continue

        # Compute max by choosing index to increment
        # Product when incrementing digit i:
        # base_prod / a_i * (a_i+1) when a_i != 0
        # Special handling when zeros exist.
        best = 0
        if zero_cnt == 1:
            # Base product is 0; only incrementing the zero digit yields non-zero.
            # Incrementing any other digit keeps a zero in the array => product 0.
            for i, d in enumerate(digits):
                if d == 0:
                    prod = 1
                    for j, x in enumerate(digits):
                        if i == j:
                            prod *= 1  # 0 + 1
                        else:
                            prod *= x
                    best = prod  # only non-zero option
                    break
            out.append(str(best))
        else:
            # No zeros: update each digit and take max
            # Use integer arithmetic
            for i, d in enumerate(digits):
                prod = 1
                # Multiply all except i, then times (d+1)
                for j, x in enumerate(digits):
                    if j == i:
                        prod *= (x + 1)
                    else:
                        prod *= x
                if prod > best:
                    best = prod
            out.append(str(best))

    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()
```

