import sys

def solve():
    it = iter(map(int, sys.stdin.buffer.read().split()))
    t = next(it)
    out_lines = []
    for _ in range(t):
        n = next(it)
        a = [next(it) for _ in range(n)]

        best = a[0]
        cur = a[0]
        for i in range(1, n):
            if (a[i] & 1) != (a[i-1] & 1):
                cur = max(a[i], cur + a[i])
            else:
                cur = a[i]
            if cur > best:
                best = cur
        out_lines.append(str(best))
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()
